import { GoogleGenAI, Type, Modality } from "@google/genai";
import { GameResponse, GameState, GameSettings } from "../types";

const API_KEY = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey: API_KEY });

// HYBRID ARCHITECTURE CONFIGURATION
const MODEL_INIT = "gemini-3-pro-preview"; // "Big Brain" for world creation
const MODEL_LOOP = "gemini-3-flash-preview"; // "Fast Brain" for gameplay actions - UPGRADED TO 3.0
const MODEL_IMAGE = "gemini-2.5-flash-image"; // "Visual Cortex" - STRICTLY NANO BANANA

// Helper to strip data:image prefix
const cleanBase64 = (dataUrl: string) => dataUrl.replace(/^data:image\/(png|jpeg|jpg);base64,/, '');

// Helper to clean JSON output using substring extraction (Most Robust)
const cleanJsonOutput = (text: string) => {
  let cleaned = text.trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
    return cleaned.substring(firstBrace, lastBrace + 1);
  }
  return cleaned;
};

// Helper: Robust JSON Parser with Auto-Repair for truncated responses
const tryParseJSON = (jsonString: string) => {
  try {
    return JSON.parse(jsonString);
  } catch (e) {
    // Attempt 1: Check if it's just missing the closing brace
    try {
        return JSON.parse(jsonString + '}');
    } catch (e2) {
        // Attempt 2: Check if it's missing a closing array and brace
        try {
            return JSON.parse(jsonString + ']}');
        } catch (e3) {
             // Attempt 3: If it ends with a quote (truncated string value), close quote and brace
             if (jsonString.trim().endsWith('"')) {
                 try {
                    return JSON.parse(jsonString + '}');
                 } catch(e4) {}
             } else {
                 // Ends in middle of string? Close quote then brace
                 try {
                    return JSON.parse(jsonString + '"}');
                 } catch(e5) {}
             }
        }
    }
    console.warn("JSON Auto-Repair failed. Original text length:", jsonString.length);
    return null;
  }
};

// Helper: Retry Logic for 503/500/404 Errors
const callWithRetry = async (fn: () => Promise<any>, retries = 3, delay = 500): Promise<any> => {
    try {
        return await fn();
    } catch (error: any) {
        // Retry on Server Errors (5xx) or if model is temporarily overloaded
        if (retries > 0 && (error?.status === 503 || error?.code === 503 || error?.status === 500 || error?.message?.includes("503"))) {
            console.warn(`API Error ${error?.status || 'Unknown'}. Retrying in ${delay}ms... (${retries} attempts left)`);
            await new Promise(res => setTimeout(res, delay));
            return callWithRetry(fn, retries - 1, delay * 2);
        }
        throw error;
    }
};

// Helper to sanitize visual prompts to avoid Safety Filters (alcohol, violence, etc)
const sanitizeVisualPrompt = (text: string) => {
    return text
        .replace(/kalimotxo|calimocho/gi, "dark red potion")
        .replace(/alcohol|wine|vino|beer|cerveza/gi, "beverage")
        .replace(/coca cola|pepsi/gi, "soda")
        .replace(/brand|logo/gi, "symbol")
        .replace(/blood|gore/gi, "red liquid")
        .replace(/kill|murder|dead/gi, "defeated");
};

const gameSchema = {
  type: Type.OBJECT,
  properties: {
    narrative: { type: Type.STRING, description: "La respuesta narrativa del juego. MÁXIMO 50 palabras. Conciso y directo." },
    location: { type: Type.STRING, description: "El nombre de la ubicación actual." },
    visualPrompt: { type: Type.STRING, description: "Descripción visual física de la escena para generar la imagen." },
    inventory: { 
      type: Type.ARRAY, 
      items: { 
        type: Type.OBJECT,
        properties: {
           name: { type: Type.STRING, description: "Nombre corto del objeto (Max 3 palabras). SIN códigos técnicos, SIN guiones bajos." },
           description: { type: Type.STRING, description: "Descripción detallada y divertida estilo enciclopedia de aventura gráfica." }
        }
      },
      description: "La lista ACTUALIZADA del inventario." 
    },
    keyElements: { 
        type: Type.ARRAY, 
        items: { type: Type.STRING }, 
        description: "Elementos visuales clave mencionados en el texto que DEBEN aparecer en la imagen." 
    },
    availableExits: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Lista de salidas visibles o direcciones posibles desde aquí."
    },
    visualChanged: { 
        type: Type.BOOLEAN, 
        description: "TRUE si la escena ha cambiado físicamente (entrar, romper, coger, abrir). FALSE si es solo diálogo o mirar." 
    }
  },
  required: ["narrative", "location", "visualPrompt", "inventory", "keyElements", "availableExits", "visualChanged"],
};

export const generateInitialGameWorld = async (settings: GameSettings): Promise<GameResponse> => {
  const prompt = `
    Act as a Lead Game Designer for a classic LucasArts style adventure game.

    GAME SETTINGS:
    - World/Universe: ${settings.world}
    - Start Location: ${settings.startLocation}
    - Art Style: ${settings.artStyle}
    - Objective: ${settings.objective}
    - Narrative Tone: ${settings.tone}

    TASK:
    Initialize the game world. Create an engaging opening scene, a protagonist description, and an initial inventory relevant to the puzzle.

    RULES:
    1. Output STRICT JSON matching the schema.
    2. Narrative must be ${settings.tone}, maximum 4 sentences. Use Typewriter style phrasing.
    3. Visual Prompt must be descriptive for an AI image generator (e.g., "Pixel art, [Style], [Details]"). 
       IMPORTANT: Do NOT include text labels, UI elements, or speech bubbles in the visual description.
    4. Inventory items MUST have natural names (e.g., "Rusty Key", "Rubber Chicken"). DO NOT use IDs like "Key_v1" or "Item_002".
    5. Plan the mystery so it's solvable.

    OUTPUT FORMAT:
    Return ONLY the JSON object.
  `;

  // FALLBACK LOGIC: Try Big Brain (Pro), if fail, use Fast Brain (Flash)
  try {
      console.log("Initializing with Gemini 3 Pro...");
      const response = await callWithRetry(() => ai.models.generateContent({
        model: MODEL_INIT,
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: gameSchema,
          // No thinking config to ensure speed/stability
          maxOutputTokens: 8192, 
        },
      }));

      const jsonText = cleanJsonOutput(response.text || "{}");
      const parsed = tryParseJSON(jsonText);

      if (!parsed || !parsed.narrative) throw new Error("Invalid JSON from Pro");

      return { ...parsed, modelUsed: "Gemini 3.0 Pro" };

  } catch (error) {
      console.warn("Gemini 3 Pro Initialization failed, falling back to Flash...", error);

      // FALLBACK: Gemini 3.0 Flash
      const response = await callWithRetry(() => ai.models.generateContent({
        model: MODEL_LOOP, // Use Flash for fallback
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: gameSchema,
        },
      }));

      const jsonText = cleanJsonOutput(response.text || "{}");
      const parsed = tryParseJSON(jsonText);
      return { ...parsed, modelUsed: "Gemini 3.0 Flash (Fallback)" };
  }
};

export const generateGameResponse = async (
    userAction: string, 
    gameState: GameState, 
    currentImageBase64: string | null
): Promise<GameResponse> => {

  // Prepare context for the AI
  const visitedList = Object.keys(gameState.knownLocations).join(", ");

  // Convert complex inventory objects to a summary string for context, but ask for full objects back
  const inventoryContext = gameState.inventory.map(i => i.name).join(", ");

  const prompt = `
    CURRENT STATE:
    - World: ${gameState.settings.world}
    - Location: ${gameState.location}
    - Current Inventory: [${inventoryContext}]
    - Visited Locations: [${visitedList}]
    - Objective: ${gameState.settings.objective}

    USER ACTION: "${userAction}"

    INSTRUCTIONS:
    1. Advance the game state based on the action.
    2. If the user picks up an item, REMOVE it from the 'visualPrompt' and 'keyElements' effectively deleting it from the scene.
    3. If the user goes to a previously visited location (or similar), use the EXACT SAME Name for 'location'.
    4. VISUALS: 
       - Set 'visualChanged' to TRUE ONLY if the physical scene changes (moving, breaking, taking). 
       - Set 'visualChanged' to FALSE for talking, looking, or thinking.
    5. INVENTORY:
       - Return the FULL inventory array. Keep existing items unless used/lost. Add new items if taken.
       - Names must be short and natural (No underscores, No codes).
    6. NARRATIVE: Keep it ${gameState.settings.tone}. Max 3 sentences.
  `;

  const parts: any[] = [{ text: prompt }];

  // Add visual context if available (Multimodal)
  if (currentImageBase64) {
      parts.push({
          inlineData: {
              mimeType: "image/png",
              data: cleanBase64(currentImageBase64)
          }
      });
  }

  const response = await callWithRetry(() => ai.models.generateContent({
    model: MODEL_LOOP, // Flash for speed
    contents: [{ role: 'user', parts }],
    config: {
      responseMimeType: "application/json",
      responseSchema: gameSchema,
    },
  }));

  const jsonText = cleanJsonOutput(response.text || "{}");
  const parsed = tryParseJSON(jsonText);

  if (!parsed) {
      throw new Error("Failed to parse game response");
  }

  return parsed;
};

export const generateSceneImage = async (
    visualPrompt: string, 
    style: string, 
    keyElements: string[] = [],
    referenceImageBase64?: string
): Promise<string> => {

  // 1. Sanitize Key Elements
  const cleanElements = keyElements
      .map(k => k.replace(/\(NPC\)|\(Item\)|\[.*?\]/g, '').trim())
      .filter(k => k.length > 0)
      .join(", ");

  // 2. Sanitize Prompt for Safety
  const safePrompt = sanitizeVisualPrompt(visualPrompt);

  // 3. Construct the Final Prompt
  // STRICTLY NANO BANANA COMPATIBLE PROMPT with Retro Styling
  const finalPrompt = `
    ${style} retro pixel art adventure game screenshot. 320x200 resolution aesthetic.
    Scene: ${safePrompt}. 
    Visible Elements: ${cleanElements}.
    NO text, NO UI, NO labels, NO speech bubbles.
    Full scene, no cropping.
  `.trim();

  console.log(`Generating Image with ${MODEL_IMAGE}...`);

  try {
      // ALWAYS USE gemini-2.5-flash-image (Nano Banana) via generateContent
      // We use generateContent for both text-to-image and image-to-image in this SDK version for Flash Image model

      const parts: any[] = [{ text: finalPrompt }];

      // If we have a reference image (editing), add it to the prompt context
      if (referenceImageBase64) {
          parts.push({
              inlineData: {
                  mimeType: "image/png",
                  data: cleanBase64(referenceImageBase64)
              }
          });
      }

      const response = await callWithRetry(() => ai.models.generateContent({
        model: MODEL_IMAGE,
        contents: { parts },
        config: {
             // Nano Banana supports responseModalities
             responseModalities: [Modality.IMAGE],
        }
      }));

      // Extract Image
      const candidates = response.candidates;
      if (candidates && candidates[0] && candidates[0].content && candidates[0].content.parts) {
          for (const part of candidates[0].content.parts) {
              if (part.inlineData && part.inlineData.data) {
                  return `data:image/png;base64,${part.inlineData.data}`;
              }
          }
      }

      throw new Error("No image data received in response");

  } catch (error) {
      console.error("Image Generation Failed:", error);

      // Retry Logic: If Editing failed, try Fresh Generation (Text-only)
      if (referenceImageBase64) {
          console.log("Retrying without reference image...");
          return generateSceneImage(visualPrompt, style, keyElements); 
      }

      // Retry Logic: If prompt was too complex/unsafe, try Simple Prompt
      if (finalPrompt.length > 100) {
           console.log("Retrying with simplified prompt...");
           const simplePrompt = `${style} pixel art scene. ${cleanElements}`;
           try {
               const simpleRes = await ai.models.generateContent({
                   model: MODEL_IMAGE,
                   contents: { parts: [{ text: simplePrompt }] },
                   config: { responseModalities: [Modality.IMAGE] }
               });
               // Extract...
               const parts = simpleRes.candidates?.[0]?.content?.parts;
               if (parts?.[0]?.inlineData?.data) {
                   return `data:image/png;base64,${parts[0].inlineData.data}`;
               }
           } catch (e) { console.error("Simple retry failed", e); }
      }

      // FINAL FALLBACK: Return a placeholder "Static/Error" image (base64)
      // A simple 1x1 gray pixel stretched, or similar. 
      // Here we return a tiny transparent pixel to let the UI handle "NO SIGNAL"
      return ""; 
  }
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GameState, GameSettings, InventoryItem } from './types';
import { generateGameResponse, generateSceneImage, generateInitialGameWorld } from './services/gemini';
import { GameScreen } from './components/GameScreen';
import { Terminal } from './components/Terminal';
import { Inventory } from './components/Inventory';
import { ActionButtons } from './components/ActionButtons';

// Default presets
const DEFAULT_WORLD = "Bilbao Realista con toques Mágicos";
const DEFAULT_LOCATION = "Bilbao, Casco Viejo";
const DEFAULT_STYLE = "Pixel Art Retro Monkey Island Style";
const DEFAULT_OBJECTIVE = "Encontrar la receta secreta del Kalimotxo legendario";
const DEFAULT_TONE = "Humor absurdo, sarcástico y nostálgico";

const VERBS = ['Ir a', 'Mirar', 'Coger', 'Hablar con', 'Usar'];

// Helpers: Aggressive Sanitization for Inventory Items
const sanitizeInventory = (items: InventoryItem[]): InventoryItem[] => {
    if (!items) return [];
    return items.map(item => {
        // Safety check for corrupt objects
        if (!item || !item.name) {
             return { name: "Objeto Glitcheado", description: "Un error en la matriz. Mejor no tocarlo." };
        }

        // 1. Remove underscores, technical suffixes, and error flags
        let cleanName = item.name
            .replace(/_/g, ' ') // Replace underscores with spaces
            .replace(/\s*-\s*ERROR\s*.*$/i, '') // Remove "- ERROR ..." tails
            .replace(/\b[a-f0-9]{8,}\b/gi, '') // Remove hex codes (hash-like)
            .replace(/x86|x64|v\d+(\.\d+)?/gi, '') // Remove version numbers
            .replace(/\s+/g, ' ') // Collapse multiple spaces
            .trim();

        // 2. Capitalize first letter just in case
        if (cleanName.length > 0) {
            cleanName = cleanName.charAt(0).toUpperCase() + cleanName.slice(1);
        }

        // 3. Truncate length for UI safety (Sidebar is narrow)
        if (cleanName.length > 22) {
            cleanName = cleanName.substring(0, 20) + '..';
        }

        // 4. Fallback if empty after cleaning
        if (!cleanName) cleanName = "Objeto Raro";

        return {
            ...item,
            name: cleanName,
            description: item.description || "Un objeto tan misterioso que la propia realidad (o la IA) se niega a describirlo. Huele a ozono."
        };
    });
};

// Map Key Normalization to improve cache hits (ignoring case/spaces)
const normalizeLocKey = (location: string) => location.trim().toLowerCase().replace(/[.,]$/, '');

// Fuzzy Location Matching to handle AI inconsistencies (e.g. "Bar" vs "Interior Bar")
const findCachedLocationKey = (targetLoc: string, knownKeys: string[]): string | null => {
    const normTarget = normalizeLocKey(targetLoc);

    // 1. Exact Match
    if (knownKeys.includes(normTarget)) return normTarget;

    // 2. Fuzzy Match (Target contains Key OR Key contains Target)
    // We sort known keys by length (descending) to match the most specific one first.
    // e.g. If known is "Bar Manolo" and target is "Bar", we might not want to match unless strict.
    // But if known is "Bar Manolo" and target is "Interior del Bar Manolo", we want to match.
    const sortedKeys = [...knownKeys].sort((a, b) => b.length - a.length);

    for (const key of sortedKeys) {
        // Ignore very short keys to prevent false positives (e.g. "A" matching "Area")
        if (key.length < 4) continue;

        if (normTarget.includes(key) || key.includes(normTarget)) {
            console.log(`[Cache] Fuzzy Match: '${targetLoc}' matched with '${key}'`);
            return key;
        }
    }

    return null;
};

export default function App() {
  // UI State
  const [isGameStarted, setIsGameStarted] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const [initStatus, setInitStatus] = useState(""); 
  const [hoveredInventoryItem, setHoveredInventoryItem] = useState<InventoryItem | null>(null);
  const [showLog, setShowLog] = useState(false); // History Log Modal State

  // Text Input State
  const [userInput, setUserInput] = useState("");
  const inputRef = useRef<HTMLTextAreaElement>(null);
  const logEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll log to bottom when opened
  useEffect(() => {
    if (showLog && logEndRef.current) {
        logEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [showLog]);

  // Menu Form State
  const [inputWorld, setInputWorld] = useState(DEFAULT_WORLD);
  const [inputLocation, setInputLocation] = useState(DEFAULT_LOCATION);
  const [inputStyle, setInputStyle] = useState(DEFAULT_STYLE);
  const [inputObjective, setInputObjective] = useState(DEFAULT_OBJECTIVE);
  const [inputTone, setInputTone] = useState(DEFAULT_TONE);

  // Game State
  const [gameState, setGameState] = useState<GameState>({
    settings: {
        world: DEFAULT_WORLD,
        startLocation: DEFAULT_LOCATION,
        artStyle: DEFAULT_STYLE,
        objective: DEFAULT_OBJECTIVE,
        tone: DEFAULT_TONE
    },
    location: '',
    narrative: '',
    inventory: [],
    availableExits: [],
    visualDescription: '',
    imageUrl: null,
    loadingStatus: null,
    history: [],
    knownLocations: {},
    modelUsed: 'Unknown'
  });

  // Start Game Logic
  const handleStartGame = async () => {
    if (!inputLocation || !inputStyle) return;

    setIsInitializing(true);
    setInitStatus("CONECTANDO CON GEMINI 3 PRO...");

    const newSettings: GameSettings = {
        world: inputWorld,
        startLocation: inputLocation,
        artStyle: inputStyle,
        objective: inputObjective,
        tone: inputTone
    };

    try {
      setInitStatus("DISEÑANDO TRAMA Y MISTERIO...");
      const initialWorld = await generateInitialGameWorld(newSettings);

      setInitStatus("RENDERIZANDO ESCENA (NANO BANANA)...");
      const imageBase64 = await generateSceneImage(
          initialWorld.visualPrompt, 
          newSettings.artStyle, 
          initialWorld.keyElements
      );

      setGameState({
        settings: newSettings,
        location: initialWorld.location || "Desconocido",
        narrative: initialWorld.narrative || "",
        inventory: sanitizeInventory(initialWorld.inventory || []),
        availableExits: initialWorld.availableExits || [],
        visualDescription: initialWorld.visualPrompt,
        imageUrl: imageBase64,
        loadingStatus: null,
        history: [{ role: 'model' as const, content: initialWorld.narrative }],
        knownLocations: {
            [normalizeLocKey(initialWorld.location || "start")]: {
                imageUrl: imageBase64,
                visualPrompt: initialWorld.visualPrompt
            }
        },
        modelUsed: initialWorld.modelUsed
      });

      setIsGameStarted(true);
    } catch (error) {
      console.error("Failed to start game:", error);
      alert("Error iniciando el motor SCUMM. Por favor intenta otra vez.");
    } finally {
      setIsInitializing(false);
      setInitStatus("");
    }
  };

  const handleAction = useCallback(async (action: string) => {
    if (gameState.loadingStatus || !action.trim()) return;

    // Optimistic UI Update
    setGameState(prev => ({ 
      ...prev, 
      loadingStatus: "ANALIZANDO ACCIÓN...",
      history: [...prev.history, { role: 'user' as const, content: action }] 
    }));

    setUserInput("");

    try {
      const response = await generateGameResponse(
          action, 
          gameState, 
          gameState.imageUrl
      );

      // Visual Logic with Persistence & Optimization
      let newImageUrl = gameState.imageUrl;
      const hasChangedLocation = response.location !== gameState.location;

      // CACHE LOGIC: Check if the new location (or a similar name) exists in memory
      const responseLocKey = normalizeLocKey(response.location || "unknown");
      const knownKeys = Object.keys(gameState.knownLocations);
      const cachedKey = findCachedLocationKey(responseLocKey, knownKeys);

      const hasVisualChange = response.visualChanged === true;

      // Optimization: Only regenerate if location changes OR explicit visual change requested
      if (hasChangedLocation) {
         if (cachedKey && gameState.knownLocations[cachedKey]) {
            // CACHE HIT: Load from memory
            console.log(`Restoring cached image for ${cachedKey}`);
            setGameState(prev => ({ ...prev, loadingStatus: "CARGANDO UBICACIÓN..." }));
            newImageUrl = gameState.knownLocations[cachedKey].imageUrl;
         } else {
             // NEW LOCATION: Generate
             setGameState(prev => ({ ...prev, loadingStatus: "GENERANDO ESCENA..." }));
             newImageUrl = await generateSceneImage(
                response.visualPrompt, 
                gameState.settings.artStyle,
                response.keyElements
             );
         }
      } 
      else if (hasVisualChange) {
         // CASE B: Same Location, but Visuals Changed (Action triggered)
         try {
            setGameState(prev => ({ ...prev, loadingStatus: "ACTUALIZANDO VISUALES..." }));

            // We pass current image as reference for editing
            newImageUrl = await generateSceneImage(
                response.visualPrompt, 
                gameState.settings.artStyle,
                response.keyElements,
                gameState.imageUrl || undefined
            );
         } catch (e) {
            console.error("Image update failed, keeping old image", e);
         }
      } 
      else {
         // CASE C: Same Location, No Visual Change (Dialogue, Looking)
         // Keep newImageUrl as is (current image)
      }

      setGameState(prev => {
        const newHistory = [...prev.history, { role: 'model' as const, content: response.narrative }];
        if (newHistory.length > 20) newHistory.splice(0, 5); // Keep buffer managed

        // Safety check for sanitizing inventory to avoid crashes
        let safeInventory: InventoryItem[] = [];
        if (response.inventory && Array.isArray(response.inventory)) {
           safeInventory = sanitizeInventory(response.inventory);
        } else {
           // Fallback to previous inventory if response is malformed
           safeInventory = prev.inventory;
        }

        // Use the cachedKey if we found one, otherwise use the new key
        const finalLocKey = cachedKey || responseLocKey;

        const updatedKnownLocations = {
            ...prev.knownLocations,
            [finalLocKey]: {
                imageUrl: newImageUrl || '',
                visualPrompt: response.visualPrompt
            }
        };

        return {
          ...prev,
          location: response.location || prev.location,
          narrative: response.narrative,
          inventory: safeInventory,
          availableExits: response.availableExits || [],
          visualDescription: response.visualPrompt,
          imageUrl: newImageUrl,
          history: newHistory,
          knownLocations: updatedKnownLocations,
          loadingStatus: null
        };
      });

    } catch (error) {
      console.error("Game Loop Error:", error);
      setGameState(prev => ({ 
        ...prev, 
        loadingStatus: null, 
        narrative: "El sistema se ha sobrecargado momentáneamente. Intenta otra acción." 
      }));
    }
  }, [gameState]);

  const handleVerbClick = (verb: string) => {
    setUserInput(currentInput => {
        const trimmedVerb = verb.trim();
        const existingVerb = VERBS.find(v => currentInput.toLowerCase().startsWith(v.toLowerCase()));
        if (existingVerb) {
            const rest = currentInput.slice(existingVerb.length).trim();
            return `${trimmedVerb} ${rest}`;
        }
        return `${trimmedVerb} ${currentInput}`;
    });
    inputRef.current?.focus();
  };

  // --- RENDER ---

  if (!isGameStarted) {
    return (
      <div className="min-h-screen bg-black text-green-500 font-vt323 flex flex-col items-center justify-center p-4">
         <div className="max-w-4xl w-full border-4 border-green-700 p-8 bg-gray-900 shadow-[0_0_50px_rgba(0,255,0,0.2)] text-center relative overflow-hidden">
           <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%)] bg-[length:100%_4px]"></div>
           <h1 className="text-6xl md:text-8xl mb-2 text-yellow-400 drop-shadow-[4px_4px_0_rgba(100,0,0,1)] animate-pulse">SCUMM-AI</h1>
           <p className="text-xl md:text-2xl text-cyan-400 mb-8 tracking-widest">CONFIGURADOR DE AVENTURA</p>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10 text-left mb-8">
             <div className="md:col-span-2 flex flex-col">
               <label className="text-lg text-green-400 mb-1">AMBIENTACIÓN / MUNDO (ej: Star Wars, Bilbao, One Piece)</label>
               <input type="text" value={inputWorld} onChange={(e) => setInputWorld(e.target.value)} className="bg-black border-2 border-green-600 text-white p-2 text-xl focus:outline-none focus:border-yellow-400"/>
             </div>
             <div className="flex flex-col">
               <label className="text-lg text-green-400 mb-1">UBICACIÓN DE INICIO</label>
               <input type="text" value={inputLocation} onChange={(e) => setInputLocation(e.target.value)} className="bg-black border-2 border-green-600 text-white p-2 text-xl focus:outline-none focus:border-yellow-400"/>
             </div>
             <div className="flex flex-col">
               <label className="text-lg text-green-400 mb-1">ESTILO GRÁFICO</label>
               <input type="text" value={inputStyle} onChange={(e) => setInputStyle(e.target.value)} className="bg-black border-2 border-green-600 text-white p-2 text-xl focus:outline-none focus:border-yellow-400"/>
             </div>
             <div className="flex flex-col">
               <label className="text-lg text-green-400 mb-1">OBJETIVO / MISIÓN</label>
               <input type="text" value={inputObjective} onChange={(e) => setInputObjective(e.target.value)} className="bg-black border-2 border-green-600 text-white p-2 text-xl focus:outline-none focus:border-yellow-400"/>
             </div>
             <div className="flex flex-col">
               <label className="text-lg text-green-400 mb-1">TONO NARRATIVO</label>
               <input type="text" value={inputTone} onChange={(e) => setInputTone(e.target.value)} className="bg-black border-2 border-green-600 text-white p-2 text-xl focus:outline-none focus:border-yellow-400"/>
             </div>
           </div>
           <button onClick={handleStartGame} disabled={isInitializing} className={`w-full max-w-md mx-auto bg-green-700 text-white text-3xl py-3 border-b-8 border-r-8 border-green-900 hover:bg-green-600 hover:border-green-800 active:translate-y-1 active:border-0 active:mb-2 transition-all ${isInitializing ? 'opacity-50 cursor-not-allowed' : ''}`}>
               {isInitializing ? initStatus : 'INICIAR AVENTURA >'}
           </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-yellow-100 p-2 md:p-4 flex flex-col items-center font-vt323">

      {showLog && (
        <div className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-gray-900 border-4 border-green-600 w-full max-w-3xl h-[80vh] flex flex-col p-4 shadow-[0_0_30px_rgba(0,255,0,0.3)]">
            <div className="flex justify-between items-center mb-4 border-b-2 border-green-800 pb-2">
              <h2 className="text-2xl text-green-400 uppercase tracking-widest">Historial de Sucesos</h2>
              <button onClick={() => setShowLog(false)} className="text-red-500 hover:text-white hover:bg-red-600 px-2 text-xl border border-transparent hover:border-white transition-colors">X CERRAR</button>
            </div>
            <div className="overflow-y-auto space-y-4 pr-4 custom-scrollbar flex-1">
              {gameState.history.map((entry, i) => (
                <div key={i} className={`p-3 border-l-4 ${entry.role === 'user' ? 'bg-gray-800 border-yellow-500 ml-8' : 'bg-black border-blue-500 mr-8'}`}>
                   <span className="text-xs uppercase tracking-wider text-gray-500 mb-1 block">{entry.role === 'user' ? 'TU ACCIÓN' : 'NARRATIVA'}</span>
                   <p className="text-lg leading-relaxed text-gray-200 font-vt323">{entry.content}</p>
                </div>
              ))}
              <div ref={logEndRef} />
            </div>
          </div>
        </div>
      )}

      <div className="w-full max-w-4xl bg-gray-800 p-2 rounded-lg border-4 border-gray-600 shadow-[0_0_20px_rgba(0,255,0,0.2)] relative">

        <div className="bg-blue-900 text-white p-2 mb-2 flex justify-between items-center border-b-2 border-black">
          <div className="flex flex-col truncate max-w-[60%]">
             <h1 className="text-2xl tracking-widest text-yellow-300 drop-shadow-md truncate">
                {gameState.location.toUpperCase()}
             </h1>
             <span className="text-xs text-cyan-300 truncate">OBJ: {gameState.settings.objective}</span>
          </div>

          <div className="flex gap-2 shrink-0">
             <button onClick={() => setShowLog(true)} className="text-xs bg-gray-700 hover:bg-gray-600 px-3 py-1 border border-black text-green-300 uppercase tracking-wider">
               LOG / HISTORIAL
             </button>
             <button onClick={() => { setIsGameStarted(false); setIsInitializing(false); }} className="text-xs bg-red-800 hover:bg-red-700 px-2 py-1 border border-black text-white">
               SALIR
             </button>
          </div>
        </div>

        <div className="flex flex-col gap-2">

          <GameScreen 
            imageUrl={gameState.imageUrl} 
            loadingStatus={gameState.loadingStatus} 
            location={gameState.location}
            hoveredItem={hoveredInventoryItem}
            availableExits={gameState.availableExits || []}
          />

          <Terminal 
            text={gameState.narrative} 
            isTyping={gameState.loadingStatus !== null}
            onShowHistory={() => setShowLog(true)}
          />

          <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mt-2 h-48 md:h-40">
            <div className="md:col-span-1 bg-black border-2 border-gray-700 p-2 overflow-y-auto">
              <ActionButtons onAction={handleVerbClick} />
            </div>
            <div className="md:col-span-1 bg-black border-2 border-gray-700 p-2">
              <Inventory 
                items={gameState.inventory} 
                onHoverItem={setHoveredInventoryItem}
              />
            </div>
            <div className="md:col-span-1 bg-black border-2 border-gray-700 p-2 flex flex-col">
               <label className="text-green-500 text-lg mb-1">¿Qué quieres hacer?</label>
               <textarea
                 ref={inputRef}
                 value={userInput}
                 onChange={(e) => setUserInput(e.target.value)}
                 disabled={gameState.loadingStatus !== null}
                 className={`flex-1 bg-gray-900 text-green-400 p-2 resize-none focus:outline-none border border-green-800 text-xl leading-tight ${gameState.loadingStatus ? 'opacity-50' : ''}`}
                 placeholder="..."
                 onKeyDown={(e) => {
                   if (e.key === 'Enter' && !e.shiftKey) {
                     e.preventDefault();
                     handleAction(userInput);
                   }
                 }}
               />
               <div className="text-gray-500 text-xs mt-1 text-right">PRESS ENTER</div>
            </div>
          </div>
        </div>
      </div>

      <footer className="mt-4 text-gray-600 text-sm text-center">
        World Gen: <span className={gameState.modelUsed?.includes("Pro") ? "text-green-500" : "text-yellow-500"}>{gameState.modelUsed || "Initializing..."}</span> <br/>
        Powered by Gemini 3.0 Pro (Brain) & Gemini 3.0 Flash (Speed) & Nano Banana (Vision) <br/> 
        World: {gameState.settings.world}
      </footer>
    </div>
  );
}
